prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msgFlow) AS ?messageFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow ;
             tai:belongsTo ?choreo ;
             bboExt:sourceRef ?taskIdOrRef .
    FILTER(STRLEN(?taskIdOrRef) > 0)
    BIND(STR(?task) AS ?taskStr)
    BIND(STRAFTER(STR(?taskStr), "#") AS ?taskLocal)
    FILTER(?taskIdOrRef = ?taskLocal)
  }

  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow ;
             tai:belongsTo ?choreo ;
             bboExt:targetRef ?taskIdOrRef2 .
    FILTER(STRLEN(?taskIdOrRef2) > 0)
    BIND(STR(?task) AS ?taskStr2)
    BIND(STRAFTER(STR(?taskStr2), "#") AS ?taskLocal2)
    FILTER(?taskIdOrRef2 = ?taskLocal2)
  }

  ?msgFlow bboExt:sourceRef ?sRef .
  FILTER(STRLEN(?sRef) > 0)
  FILTER( (
     EXISTS {
       FILTER(STR(?task) != "")
     }
  ) )

  OPTIONAL { ?task bbo:name ?taskName . }
}
GROUP BY ?task ?taskName
HAVING (?messageFlowCount > 1)
ORDER BY DESC(?messageFlowCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msgFlow) AS ?messageFlowCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }

  ?msgFlow a bboExt:MessageFlow ;
           tai:belongsTo ?choreo ;
           bboExt:sourceRef ?sRef ;
           bboExt:targetRef ?tRef .

  FILTER( (
     (BOUND(?sRef) && FILTER(CONTAINS(STR(?task), ?sRef)))
     ||
     (BOUND(?tRef) && FILTER(CONTAINS(STR(?task), ?tRef)))
  ))
  )
}
GROUP BY ?task ?taskName
HAVING (COUNT(DISTINCT ?msgFlow) > 1)
ORDER BY DESC(?messageFlowCount)
LIMIT 25

