SELECT DISTINCT ?choreo ?msgFlow ?msgFlowName ?sRef ?tRef ?sTask ?sTaskName ?tTask ?tTaskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "sid_ece51571_13ba_41d8_8688_057c876cc093" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

