  OPTIONAL {
    ?sTask a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo .
    ?sTask bbo:name ?sTaskName .
    FILTER(STRENDS(STR(?sTask), ?sRef) || STRLEN(?sRef)=0)
  }
  OPTIONAL {
    ?tTask a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo .
    ?tTask bbo:name ?tTaskName .
    FILTER(STRENDS(STR(?tTask), ?tRef) || STRLEN(?tRef)=0)
  }
